import React from "react";

export default function SettingPage() {
  return (
    <div className="bg-white min-h-screen flex flex-col items-center">
      {/* Container chính */}
      <div className="max-w-[1440px] w-full flex flex-col px-20 mt-12">
        
        {/* Các mục setting */}
        <div className="flex flex-col flex-1 gap-4 mt-6">
          <div className="bg-[#C6E1FF85] py-3 px-6 rounded-md">
            <span className="text-black font-bold text-base">Đổi mật khẩu</span>
          </div>
          <div className="bg-[#C6E1FF85] py-3 px-6 rounded-md">
            <span className="text-black font-bold text-base">Thông báo</span>
          </div>
          <div className="bg-[#C6E1FF85] py-3 px-6 rounded-md">
            <span className="text-black font-bold text-base">Quyền riêng tư</span>
          </div>
        </div>

        {/* Nút đăng xuất */}
        <div className="flex justify-center mt-12 mb-8">
          <button className="bg-[#FFDEF8CF] py-2 px-10 rounded-[20px] font-medium text-black">
            Đăng xuất
          </button>
        </div>
      </div>
    </div>
  );
}
